INSERT INTO procedure_items (section_number, section_name, control_question, evidence_required, tims_ref, sort_order) VALUES
('1', '1. Leadership', '1.1 Organisational Structures Maintained and Approved', '', '', 1),
('1', '1. Leadership', '1.2 Vacancy plan developed, implemented, monitored and maintained.', '', '', 2),
('1', '1. Leadership', '2.  How are the roles, authorities and responsibilities of leadership regarding TIMS implemented?  (TIMS Roles, Authority and Responsibility Framework as per Annexure 8.1 TIMS Roles Authorities and Responsibilities Framework)', '2. Job description include TIMS requirements', '', 3),
('1', '1. Leadership', '3. Which  TIMS Appointments that are in place and what process have been followed to maintain them? ( Annexure 8.3 TIMS Appointment Guidelines and Annexure 8.4 Appointment Letter Template.)                                    TIMS Element 1: Clause 6.6.2                                        6.6.1 Statutory Appointments', '3. Statutory and other Operational Appointments  letters in place and maintained according to the relevant requirements.                                                -IMS Administrator; -IMS Coordinator; -SHE Committee Co-opted Member                                                             - First Aider                                                                 -SHE REP: Section 17 of the OHSA (Act 85 of 1993) by the IMS Coordinator                                                           -General Machinery Regulation 2 (7)                                                             -etc', '', 4),
('1', '1. Leadership', '4. How is the Delegation of Authority maintained and monitored for all the cost center owners.                             TIMS Element 1 Clause 6.5', '4. Approved current Delegation of Authority and Matrix for all the cost center owners.', '', 5),
('1', '1. Leadership', '5. How is the security deployment coordinated?', 'Deployment plan based on risk / hot spots', '', 6),
('1', '1. Leadership', '6. How is the implementation of the TIMS monitored? TIMS Element 1 Clause: 6.8.2 Safety, Health and Environmental (SHE) Committees', 'SHEQ Meeting minutes, adherence to agenda and attendance registers (Schedules and adherance)', '', 7),
('1', '1. Leadership', '7. Was the suitability, effectiveness and adequacy assessed?', 'SHEQ Meeting minutes and attendance registers', '', 8),
('1', '1. Leadership', 'Management Reviews scheduled  as per the procedure TIMS Element 1 Clause: 6.8.1.3 Levels of Management Review', 'Meeting Schedule available on TIMS Sharepoint Workspace', '', 9),
('1', '1. Leadership', 'Management Review Schedule is communicated', 'Communication Memo available on TIMS Sharepoint Workspace', '', 10),
('1', '1. Leadership', 'Management Reviews are conducted as per schedule at Group level/OD level', 'Attendance Registers, Minutes and Management Review Meetings Pack/Report available on Sharepoint', '', 11),
('1', '1. Leadership', 'All applicable  Management Review data to be made available', 'Attendance Registers, Minutes and Management Review Meetings Pack/Report available on Sharepoint', '', 12),
('2', '2. Policy', '1. Has top management established, implemented and maintained TIMS Policy  that: a) is appropriate to the purpose and context of the organization and supports its strategic direction? b) provides a framework for setting TIMS objectives. c) includes a commitment to satisfy applicable requirements and Continual Improvement?', 'Available and displayed Policy', '', 12),
('2', '2. Policy', '2. Is the TIMS Policy being discussed in the SHEQ Committee, review meeting and other forums to reiterate commitment of management?', 'Minutes of Meeting and Attendance Registers', '', 13),
('2', '2. Policy', '3. Is the revised TIMS Policy statement displayed in prominent common areas and notice boards? Does local management and employees understand the TIMS policy?                                                                              TIMS Element 2 Clause 6.5. Communication of the TIMS Policy Commitment Statement', 'Check notice boards and common areas Assess the level of unuderstanding of the policy?', '', 14),
('2', '2. Policy', '4. Has the Stakeholder TIMS Policy Commitment Statement Request Register been developed and/or updated?', 'Updated Stakeholder TIMS Policy Commitment Statement Request Register', '', 15),
('3', '3. General Requirements', '1. How was the identification of scope and boundaries conducted? 2.  Is the scope of the organization’s quality management system available and maintained as documented information?How was the identification of scope and boundaries conducted?', '1. Business unit scope documented', 'Yes', 16),
('3', '3. General Requirements', '2. Does the scope state the types of products and services covered, and provide justification for any general requirement of the procedure that the organization determines is not applicable to the scope of its quality management system?                                        TIMS Element 3 Clause 6.2.3 TIMS Scope', '1. Business unit scope documented stating product and services covered. 2. Justification evidence where standard requirements is not applicable to the scope.', '', 17),
('3', '3. General Requirements', '3. Explain and give evidence of the TIMS Scope (General requirements)?', 'Mandate, context of organisation, physical boundaries  (area, depot, business unit, specialist unit or departmental, business activities, exclusion etc)', 'Yes', 18),
('4', '4. Operational  Risk Management', '1. Confirm if the Operational Risk Assessment Register was conducted using the latest Risk Assessment Register Format. (This may also include testing the approach in identifying activities, hazards, risks and opportunities. NB: this is the overall evaluation of complaince to the procedure and quality of input.)                                                                                       TIMS Element 4 Clause 6.2.3. Identification of Risk Process', '1. Final Operational Risk Assessment register for the year under review in the latest Risk Assessment Register Format. Compliance to the process and quality of the input.', '', 19),
('4', '4. Operational  Risk Management', '2. Does the Risk Register cover all operational areas of the business including outlying operations?', '1. Documented work areas verification', '', 20),
('4', '4. Operational  Risk Management', '3. Adequate identification of controls to mitigate the identified risk including the monitoring on the effectiveness of controls deployed for the risk.', '1. Updated risk register, attendance register as proof of involvement of relevant stakeholders 2. Control Assessments through inspection reports, PJOs, etc. 3. All risk register fields completed', '', 21),
('4', '4. Operational  Risk Management', '4. Have the top ten (10) risks/aspects been identified and management plans formulated to mitigate those risks?                                                                                  TIMS Element 4 Clause: 6.7. Determination of Top 10 Significant Risks/Impacts per category', '3. Documented management plans for the identified top 10 significant risks including evidence of implementation.', '', 22),
('4', '4. Operational  Risk Management', '5. How are the Changes identified, monitored and assessed for the risk introduced?', '1. Any record of changes within the review period. Adherence to the Management of Change Procedure. Issue based Risk Register for the change. (These are at local level, where applicable)', '', 23),
('4', '4. Operational  Risk Management', '6. How are the new technology and equipment''s introduced,risk assessed, implemented and monitored?', '1. Any record of new equipment, technology within the review period. Issue based Risk Register for the introduced equipment of technology.', '', 24),
('4', '4. Operational  Risk Management', '7. Is the risk assessment amended after occurrences?', '1. Amendment made after an occurrences and records of that amendment.', '', 25),
('4', '4. Operational  Risk Management', '8. Has the risk register been communicated to employees and interested parties?                                         TIMS Element 4 Clause: 6.10. Risk Assessment Communication                                             OHSA NO 85 of 1993 Section 8 (i)', '4. Attendance register with signatures or e-mails', '', 26),
('4', '4. Operational  Risk Management', '10. Is the operational risk management from a multi-disciplinary approach?', '1. Attendance register with multi-disciplinary team                                                           2. Risk Register with various catergories per applicable risk', '', 27),
('4', '4. Operational  Risk Management', '11. Is the operational risk management based on business work areas or main processes and activities/services?', '1. Work areas or main processes and activities/services process flow                                   2. Risk Register linked to the process flow', '', 28),
('4', '4. Operational  Risk Management', '12. Are opportunities explored for identification during the risk assessment?  TIMS Element 4- Clause: 6.13 Management of Opportunities', '1. Opportunities Register', '', 29),
('4', '4. Operational  Risk Management', '13. Is operational risk assessment periodically reviewed annualy by a multi-disciplinary team?', '1. Operational risk assessment review schedule    2. Attendance register of multi-disciplinary team', '', 30),
('4', '4. Operational  Risk Management', '14. Are records of risk registers, attendance registers and opportunity registers kept for a period of at least 3 years or as per statutory or regulatory requirements?', '1. Records of at least 3 years', '', 31),
('5', '5. Compliance Obligations', '1. What are the inputs to the identification of the compliance obligations?', '1. Applicable national and international regulatory requirements 2.Applicable by laws 3. Applicable Codes and Standards  4. Transnet codes, processes, systems, activities, people, products and services', '', 32),
('5', '5. Compliance Obligations', '2. Are the compliance obligations identified, assessed and communicated?', 'Compliance Obligation universe Compliance register', '', 33),
('5', '5. Compliance Obligations', '3. Are the require permits identified, maintained and updated in the licence and permit register?                                                    TIMS Element 5 Clause: 6.3 License and Permit Management', 'Licence and permit register  (e.g. Environmental permits, Compliance to conditions of permits, COP 29 certificates and licences, Railway operations permits, Gas Store, Flammable store, Affluent Plant, Spray Booth, etc.)', '', 34),
('5', '5. Compliance Obligations', '4. How are licence conditions monitored?                                  TIMS Element 5 Clause: 6.6 Review of the Compliance Obligations', 'Action plans', '', 35),
('5', '5. Compliance Obligations', '5. How are the compliance (prohibition, contraventions, improvement notices and directives) non-conformance being monitored, managed and addressed?', '1. Compliance exposure report         2. Implementations of actions and assess effectiveness (improvement directives, contraventions and prohibitions) 3. Reporting of Compliance exposure report to the governance committees', '', 36),
('5', '5. Compliance Obligations', '6. Have the RSR Permit Conditions communicated, monitored and addressed?', 'Register / email / Governance forum minutes Implementations of action plan', '', 37),
('6', '6. Objectives, Targets and Programmes', '1. What inputs were used to develop the Objectives and targets? TIMS Element 6-Clause: 6.1 Setting of Objectives and Targets', '1. Objectives and Targets developed in relation with the significant/very high SHEQ risks or opportunities derived from; Overall business strategy and context; Stakeholders (customers, employees, etc.) requirements and expectations; Compliance obligation (legislation, standards, etc.)  TIMS Operational Risk assessments;  Past performance against established Key Performance Indicators;  Occurrences, noncompliance, directives from authorities;  Outcomes of internal and external audits;  Resources capacity (technology, finance, human capital, etc.) and etc.', '', 38),
('6', '6. Objectives, Targets and Programmes', '2. How are the Objectives and targets documented, communicated, monitored and maintained? Are management plans applicable to the business and effectively implemented and monitored to mitigate the risks?                                                                                         Communication: TIMS Element 6 Clause: 6.5 Consultation and Communication of Objectives, Targets and Management  Plans.                                                                                  Management Plans: TIMS Element 6 Clause: 6.3 Objectives and Targets Key Performance Indicators', 'Management Plans (e.g SIP, Environmental programme, operational plans)  Meeting minutes and attendance register Status report (e.g Performance Report) Three yearly review cycle and annual progress review', '', 39),
('6', '6. Objectives, Targets and Programmes', '3. Are Objectives & Targets and Management Plans   Specific, Measurable, Achievable Realistic and Timely addressed?                                                                           TIMS Element 6 clause: 6.1 Setting of Objectives and Targets', 'SMART Objectives and Targets,   - , allocated sufficient resources, and delegated to responsible persons.', '', 40),
('6', '6. Objectives, Targets and Programmes', '4. How are the progress of the Management Plans monitored? At what forums are these management plans communicated and monitored? What is the current state of implementation/completion (Progress)?                                 TIMS Element 6 Clause: 6.6 Monitoring and Reporting on Objectives, Targets and Management Plans', '4. Management Plan reports', '', 41),
('7', '7. Stakeholder Management', '1. How is the Internal and External communication managed?', '1. Internal Communication: newsletters, notice board, emails, meetings,  ‘Toolbox talks’, digital signboard, social media, Teleconference, Suggestion box, Intercom system, Events, Reports, Phone Calls, Internal Magazine and Management Review Meetings External Communication:  Media Relations, Reports of incidents to Authorities, Designated appointed personnel', '', 42),
('7', '7. Stakeholder Management', '2. What process was followed to identify the internal and external stakeholders?', '1. Stakeholders with influence/impact on the organisation 2. Stakeholders importance to the organisation', '', 43),
('7', '7. Stakeholder Management', '3. Are the Stakeholders identified, analysed, and ranked?', 'Completed Ranking Matrix', '', 44),
('7', '7. Stakeholder Management', '4. Have he methods of engagement identified for each stakeholder? TIMS Element Clause: 7 6.2.2. STEP 2: Develop Engagement Plans and Engage', 'Stakeholder Engagement Plan', '', 45),
('7', '7. Stakeholder Management', '5. How are the issues monitored and evaluated?', '1.  Review and assessment of information received from stakeholders pertaining to real and perceived impacts on our business. 2. Materiality determined for issues  3. Rating of the issues are rated ( scale of 1-10, 1 being low and 10 being high).  4. Grouping of the issues into 4 levels of materiality  5. Proactive identification of potential impacts to business as part of stakeholder analysis, and identify feasible solutions to reduce impacts as far as practicable. 6. Identification and evaluation of potential issues with stakeholders  7. Escalation of the relationships that pose a high risk to Top Management and reporting of this risks to the relevant governance committee', '', 46),
('7', '7. Stakeholder Management', '6. Who is responsible to monitor and evaluate the issues?', 'Appointed Stakeholder Relationship Officer', '', 47),
('7', '7. Stakeholder Management', '7. Is the annual and quarterly Stakeholder Engagement and Management Report generated?', 'Report shall include, but not limited to: · List of stakeholders for the reporting cycle; · Method and frequency of engagements for the reporting cycle; · Objectives of the engagements; · Issues raised, responses to those issues as well as actions taken; · Potential impacts to business and · Areas of improvement;', '', 48),
('7', '7. Stakeholder Management', '8. How is Stakeholder Improvement Plan developed, monitored and maintained?', 'Completed Stakeholder Improvement plans', '', 49),
('7', '7. Stakeholder Management', '9. Which process is followed for Consultation and Participation process?', '1. Define Strategy defined as follows: - Define the objectives of the consultation and participation - Stakeholder mapping - Selection of the most appropriate methods and tools for consultation and participation - Define the timing and duration of consultation and participation 2. Run a Consultation and Participation Process: - Select the Consultation and Participation Medium and Space  – Announcement/ Communication of consultation and participation  – Undertake the consultation and participation process - Acknowledge receipt of contributions received 3. Analyse Results: - Analyse the responses - Reporting on the results and providing feedback  – Evaluation of consultation and participation exercise', '', 50),
('7', '7. Stakeholder Management', '10. Is the Community Grievance Mechanism being used?', '1. Log a Case 2. Assign a Case 3. Investigate/Compile a Case 4. Finalise a Case 5. Report on Community Grievance Outcomes 6. Submit for Integrated Reporting', '', 51),
('8', '8. Competencies, Awareness & Training', '1. Has the Technical and compliance training skills matrix developed and maintained?                                                     TIMS Element 8- Clause 6.1.3 Skills Clustering and Competency Modelling', 'Completed skills matrix Training plan  Status report', '', 52),
('8', '8. Competencies, Awareness & Training', '2. How is implementation of the OBML (Artisans) being managed, monitored and maintained?', '', '', 53),
('8', '8. Competencies, Awareness & Training', '3. How is the OBML programme being managed, monitored and improved?', '1. OBML Matrix and schedule 2. Update the Candidate’s Profile (theoretical assessment, practical assessment, and comprehensive assessments) 3. Status report of the OBML assessment  4. Completed Assessment Effectiveness Evaluation', '', 54),
('8', '8. Competencies, Awareness & Training', '4. What is the process followed for the Task observation process?', '1. Task Observation schedule  2. Status update of the task observation plan 3. Management of actions identified', '', 55),
('8', '8. Competencies, Awareness & Training', '5. How is overtime managed to prevent fatigue?', 'Overtime report Resoultion of the deviations', '', 56),
('8', '8. Competencies, Awareness & Training', '6. Are the Performance Contracts and Individual Development Plan developed, maintained and updated?', 'Employee Balanced Scorecard (BSC) and Individual Development Plan (IDP). BSC’s and  IDP’s maintained on SAP.', '', 57),
('8', '8. Competencies, Awareness & Training', '7. Does the business have ongoing plans to train personnel on TIMS procedure, TIMS SharePoint, IsoMetrix and other TIMS related internal systems?', 'Training and awareness plans, and attendance registers.  Posters and flyers', '', 58),
('8', '8. Competencies, Awareness & Training', '8. During ongoing awareness, were the following comunicated to the employees ?   the risks associated with his/her job;  relevant Organisational Policies;  IMS Objectives;  New technology;', 'Applicable Training / Attendance  registers', '', 59),
('8', '8. Competencies, Awareness & Training', '9. Does the job profiles / descriptions contains the following ?  Competencies   Education   experience required to fulfil the requirements of any job', 'Job descriptions', '', 60),
('9', '9. Operational Planning and Control', '1. Are business processes documented, maintained, managed, available in a common repository and listed in a register?', 'Business Process Register', '', 61),
('9', '9. Operational Planning and Control', '2. How are the changes of the business processes being managed?', 'Change Register', '', 62),
('9', '9. Operational Planning and Control', '3. Management of the outsourced service i.e Interaction with OEM''s, waste and services contractors?', '1. Communication of the plans 2. Monitoring of the plans 3. Addressing the gaps where plan was not met', '', 63),
('9', '9. Operational Planning and Control', '4. Management of Speed Monitoring on motorised  vehicles, plans, the implementation of the plans and management of the deviations', '1. Schedule 2. Status report 3. Action plans', '', 64),
('9', '9. Operational Planning and Control', '5. Management of the transportation of goods, material to outlying depots', '1. Loading profiles 2. MSDS availability 3. Route risk assessment 4. Training of the personnel handling', '', 65),
('9', '9. Operational Planning and Control', '6. Management of detonators (009-TE-MS-SAF-8077)                                                                                                                                                                                                                                                                                                                                                                                                                                (EA) EXPLOSIVES ACT 15 OF 2003 Chapter 3 (15)', '1. Storage 2. Permit 3. Training of the personnel handling the detonators', '', 66),
('9', '9. Operational Planning and Control', '7. Management of the substance abuse', '1. Random alcohol testing 2. Drug testing 3. Disciplinary statistics', '', 67),
('9', '9. Operational Planning and Control', '8. Management of overtime and call outs? Is overtime worked per employee in line with BCEA regulations?', '1. Approved overtime memoranda  2. Overtime report and employees working excessive overtime', '', 68),
('9', '9. Operational Planning and Control', '9. How are the yard / siding SWP review, verification, turnaround time being managed? Are the yards well resourced and vacancies filled on time?', '1. Vacancies report 2. Cycles times reports', '', 69),
('9', '9. Operational Planning and Control', '10. Does the business meet its reliability and availability obligations to the client (rolling stock and machinery)?', '1. Availability and Reliability Statistics 2. Action plans to address deviations', '', 70),
('9', '9. Operational Planning and Control', '11. Does the business have a reliable supply of material and components to deliver a quality products and meet client demands?', '1. List of critical components and current stock levels (you can also check past history)', '', 71),
('9', '9. Operational Planning and Control', '10. How is the PCBs, historic pollution, asbestos process managed, monitored and resolution of the actions?', '1. Historic pollution, asbestos, PCB management programme (plan, testing reports etc) 2. Programme Status report 3. Action plans', '', 72),
('9', '9. Operational Planning and Control', '12. How is waste, scrap and recycling managed in the business?', '1. Waste separation programme (colored binse) 2. Check adherence 3. Recycling records and safe storage of scrap in the premises', '', 73),
('9', '9. Operational Planning and Control', '13. Does the organization preserve the outputs during production and service provision, to the extent necessary to ensure conformity to requirements?', 'Preservation can include identification, handling, contamination control, packaging, storage, transmission or transportation, and protection', '', 74),
('9', '9. Operational Planning and Control', '14. Does the organization meet requirements for post-delivery activities associated with the products and services?', 'Post-delivery activities can include actions under warranty provisions, contractual obligations such as maintenance services, and supplementary services such as recycling or final disposal.', '', 75),
('9', '9. Operational Planning and Control', '15. How is crime prevention managed?', '1. Identification of hot spots 2. Preventive and response plan 3. Risk arising from theft (analysis security incidents)', '', 76),
('10', '10. Document, Data and Records Management', '1. Are all documents current, controlled and accessibile as per the Document, Data and Records Management procedure?  Management of obsolete documents', '1. Current documents and available at the point of use.', '', 77),
('10', '10. Document, Data and Records Management', 'Are the documents of external source (i.e. clients, service providers, contractors, consultants, regulators etc.) being managed? Can be extracted from SharePoint as and when required.', '1. Document register 2. Electronic copies of the original paper documents managed within the approved system. 3. Links added in an applicable software system to the electronic scanned copies. 4. Descriptive details (metadata) of these documents are captured on the applicable Transnet document management system.', '', 78),
('10', '10. Document, Data and Records Management', 'How are the TIMS documents and records maintained, controlled and administered within the electronic management systems?', '1. Communication of the approved New or Updated Procedures 2. Records Disposal Register 3. Completed document Control Change Request 4. Records Retention Guide. 5. Certificate of secure and compliant destruction', '', 79),
('11', '11. Product Lifecycle Management', '1. In communicating with the customers are the following discussed and agreed upon?   Information relating to the Products and Services                                                       Customer Feedback  Handling and controlling customer Product', '1. Statement of work (SOW) 2. Specifications, etc 3. Customer Surveys', '', 80),
('11', '11. Product Lifecycle Management', '2. Are the following requirements for Products and services stipulated?  Statutory and Regulatory requirements                            Those considered necessary by the organization', '1. Requirements noted / listed / communicated', '', 81),
('11', '11. Product Lifecycle Management', '3. Are Changes of Requirements documented and discussed / Awareness conducted ?', '1. Change documentation and records  2. Attendance Registers', '', 82),
('11', '11. Product Lifecycle Management', '4. Was there a project requirements gathering and analysis?', '1. Project File                                                      2. Project meeting agenda and minutes', '', 83),
('11', '11. Product Lifecycle Management', '5. Were all interested parties involved in the requirements gatering and analysis', '1. Meeting invite                                                    2. Meeting attendance register', '', 84),
('11', '11. Product Lifecycle Management', '6. Were all activities (minimum all mandatory) activities completed during meeting ?', '1. Meeting minutes                                             2. Action plans with responsibility, due date and status', '', 85),
('11', '11. Product Lifecycle Management', '7. Were all milestone activities met to proceed from project requirements gathering and analysis to the next phase?', '1. Signed-off user requirements specification for the project.', '', 86),
('11', '11. Product Lifecycle Management', '8. Was design and development process followed for the project?', '1. Project File                                                      2. Project meeting agenda and minutes', '', 87),
('11', '11. Product Lifecycle Management', '9. Was a letter of intent or authorising document available to initiate the design and development process?', '1. Letter of Intent/ authorising document date        2. Meeting minutes/Action plans', '', 88),
('11', '11. Product Lifecycle Management', '10. Were all interested parties involved in the design and development', '1. Meeting invite                                                    2. Meeting attendance register', '', 89),
('11', '11. Product Lifecycle Management', '11. Were all activities (minimum all mandatory) activities completed during design and development phase ?', '1. Meeting minutes                                             2. Action plans with responsibility, due date and status', '', 90),
('11', '11. Product Lifecycle Management', '12. Was the change management process adopted to manage changes after the design freeze?', '1. Change management process                               2. Design change tracking sheet', '', 91),
('11', '11. Product Lifecycle Management', '13. Was the project design validated through pilot/prototype?', '1. Pilot/Prototype approval                                       2. Date of Pilot/Prototype approval', '', 92),
('11', '11. Product Lifecycle Management', '14. Were all milestone activities met to proceed from design and development to the next phase?', '1. Operational readiness and commissioning sign-off.', '', 93),
('11', '11. Product Lifecycle Management', '13. Was operational readiness and commissioning sign-off before start of project industrialisation/ commissioning/roll-out?', '1. Operational readiness and commissioning sign-off.                                                                   2. Project plan', '', 94),
('11', '11. Product Lifecycle Management', '15. Were all (minimum all mandatory) activities completed during construction/development/ manufacturing phase ?', '1. Project plan                                             2. Project Status reports', '', 95),
('11', '11. Product Lifecycle Management', '16. Were all construction /development/ manufacturing completed before commissioning?', '1. Project plan                                              2. Project Status reports', '', 96),
('11', '11. Product Lifecycle Management', '17. Did end-users form part of the commissioning and acceptance process and needs and expectations met?', '1. Commissioning report                                    2. Project NCR information', '', 97),
('11', '11. Product Lifecycle Management', '18. Was a letter of intent or authorising document available to initiate the maintenance process/project?', '1. Letter of intent or authorising document', '', 98),
('11', '11. Product Lifecycle Management', '19. Was maintenance executed as per letter of intent or authorising document strategy, e.g. preventative or time-based or distance-based or condition-based or performance-based or corrective and run-to-failure amongst others?', '1. Letter of intent or authorising document              2. Billing information', '', 99),
('11', '11. Product Lifecycle Management', '20. Did the maintennace strategy at minimum include all mandatory activities for maintenance project?', '', '', 100),
('11', '11. Product Lifecycle Management', '21. Was maintennace strategy applicable to the asset base with condition assessments conducted and recorded as prescribed?', '1. Condition assessment report', '', 101),
('11', '11. Product Lifecycle Management', '22. Are all maintenance plans managed by the approved maintenance management System?', '1. Approved maintenance plans in the system', '', 102),
('11', '11. Product Lifecycle Management', '23. Did the decommissioning/disposal take into consideration all relevant legislative and other requirements', '1. Disposal documents                                      2. Scrappring documents', '', 103),
('11', '11. Product Lifecycle Management', '24. Did the decommissioning/disposal classify the strategy as rehabilitation or redeployment or recycling or cascading or decommissioning and deconstruction or heritage amongst others?', '', '', 104),
('11', '11. Product Lifecycle Management', '25. Did the decommissioning/disposal strategy at minimum include all mandatory activities for decommissioning/disposal phase?', '', '', 105),
('11', '11. Product Lifecycle Management', '26. Was decommissioning/redeployment/disposal of a product done responsibly and considered current relevant legislations?', '', '', 106),
('11', '11. Product Lifecycle Management', '27. Were records for Requirements Gathering and Analysis/Design and Development/Industrialization/ Commission/Roll-out/Maintenance/Decommissioning/ Disposal kept for a period of at least three years or as required by statutory and regulatory requirements?', '1. Records of at least 3 years for each of the Life Cycle stages.', '', 107),
('11', '11. Product Lifecycle Management', '28. Did the decommissioning/disposal classify the strategy as rehabilitation or redeployment or recycling or cascading or decommissioning and deconstruction or heritage amongst others?', '', '', 108),
('11', '11. Product Lifecycle Management', '29. Did the decommissioning/disposal strategy at minimum include all mandatory activities for decommissioning/disposal phase?', '', '', 109),
('11', '11. Product Lifecycle Management', '30. Was decommissioning/redeployment/disposal of a product done responsibly and considered current relevant legislations?', '', '', 110),
('11', '11. Product Lifecycle Management', '31. Were records for Requirements Gathering and Analysis/Design and Development/Industrialization/ Commission/Roll-out/Maintenance/Decommissioning/ Disposal kept for a period of at least three years or as required by statutory and regulatory requirements?', '1. Records of at least 3 years for each of the Life Cycle stages.', '', 111),
('12', '12. Interface Management', '1. Identification of Intrafaces  amongst various OD''s (e.g. Management of SLA between TE & TFR Assurance activities aligned to the SLA, Security arrangment when sharing facilities, Integration of facility management between various OD’s (Environmental Management Committees))', '1. Service Level Agreements; · Siding Agreements; · Section 56 Agreements & 57 Licenses (NPA); · Access Agreements; Service Level Agreements; 2. Interface register and agreements.', '', 112),
('12', '12. Interface Management', '2. Validity of Interface agreement, interface register and the monitoring of interfaces as per agreement Interface management  -(e.g. agreements with municipalities and other stakeholders, Interface register and Interface meeting)                                      TIMS Element 12 Clause: 6.2 Development of Interface Agreements', 'Interface Agreements Register.', '', 113),
('12', '12. Interface Management', 'How are the interface Management engagements coordinated, scheduled and implemented? Is it aligned to Risk Assessment outcome?', '1. Engagement schedule 2. Minutes and attendance register', '', 114),
('12', '12. Interface Management', '3. Alignment between iSCM and Safety i.e. availability of PPE, uniform', '', '', 115),
('12', '12. Interface Management', '4. Verify if monitoring interface agreements and its frequency influenced by the outcome of the Risk Assessment', '· Audits/inspections · Meetings · Workshops · Awareness · BCM/Emergency Situations/JOCs · Informal Engagements', '', 116),
('12', '12. Interface Management', '5. How are the deviations and opportunities for improvement managed, monitored and implemented within set timelines?', 'Non-conformance report Action plan status report', '', 117),
('12', '12. Interface Management', '3. Does a risk assessment take place prior to the review of the interface agreement? (This is to ensure that all potential risks are mitigated and controlled in the newly revised interface agreement)', 'Risk register', '', 118),
('12', '12. Interface Management', 'Verify if the Interface agreements were assessed, evaluated or reviewed as per specified in the interface agreement register or based on changes?', 'Revised / updated Interface agreement Triggers for change of interface agreements include but not limited to the following: · New or amendments of the operational processes; · Occurrences and Lessons learnt; · Compliance Obligations (New or revised standards, legislation, internal policies and procedures; etc.)', '', 119),
('13', '13.  Occurrence & Non-Conformity Management', '1. How is the occurrence notification being reported, classified and reported to the relevant personnel / authorities / stakeholders? (Take a sample of level 1 &2, 50% of 3&4)', 'Railway Occurrence: Annexure 8.8, Railway Occurrence Management Process Flow; Injury on Duty: Annexure 8.9 Injury on Duty Management Process Flow; Occupational Diseases and Illnesses: Annexure 8.10 Occupational Diseases & Illnesses Occurrence Management Process Flow; Environmental Occurrence: Annexure 8.11 Environmental Occurrence Management Process Flow; Asset and Property Damage (including Motor Vehicle) Occurrence: Annexure 8.13 Asset and Property Damage (including Motor Vehicle) Occurrence Management Process Flow; Security Occurrence: Annexure 8.14 Security Occurrence Management Process Flow; HAZMAT, Fire, Explosion and Other Safety Occurrences:  Annexure 8.15 HAZMAT Fire, Explosion and Other Safety Occurrences Management Process Flow', '', 120),
('13', '13.  Occurrence & Non-Conformity Management', '2. Are draft reports for occurrences completed and circulated within in 15 calendar days?', 'Sample recent occurences (Level 1 & 2)', '', 121),
('13', '13.  Occurrence & Non-Conformity Management', '3. Is the end to end process from the time of occurrence to the closure of the corrective and preventive actions follow for every occurance?', '1. Check completion of the occurance notifications reports (Level 1 & 2), preliminary reports, investigation reports, CAP Register, NCRs and Action plans', '', 122),
('13', '13.  Occurrence & Non-Conformity Management', '4. Does the appointed Incident Commander take charge at occurance scenes and complete the necessary documentation according to the nature and level of occurance?', 'Appointments letter and training certificate of the Incident Commander', '', 123),
('13', '13.  Occurrence & Non-Conformity Management', '5. How is the corrective and preventive action monitored? (Take a sample of 2020/2021 and Q1 2021/22)', '1. Effective close out of the findings in the systems with the objective evidence. 2. Status report from IsoMetrix 3. Records on TIMS SharePoint', '', 124),
('13', '13.  Occurrence & Non-Conformity Management', '4. Are the investigators competent? (Take a sample of 2019/20 and Q1 2020/21)', 'Training Certificates', '', 125),
('13', '13.  Occurrence & Non-Conformity Management', '6. How are the investigation reports validated for correctness prior to sign-off? (Take a sample of 2020/22 and Q1 2021/22)', 'Investigation report', '', 126),
('13', '13.  Occurrence & Non-Conformity Management', '7. What process used to manage occurrence sites?', 'Preservation of evidence in line with Section 24 of the OHS Act 85 of 1992, Clearance of the occurrence site e.g. rehabilitationof the incident site', '', 127),
('13', '13.  Occurrence & Non-Conformity Management', '8. How is effectiveness of the closure of incident verified? (evidence available)', 'Closed investigation report', '', 128),
('13', '13.  Occurrence & Non-Conformity Management', '9. Is the Risk Assessment Register reviewed after major occurences?', '1. Proof of Risk Assessment Register review as a result of an occurance 2. Attendance register', '', 129),
('14', '14. Contractor Management', '1. Communication between Head Office and Areas on Contract Management  - Roles and responsibilities when arriving on-site', '1. Interface agreements (SLA''s).', '', 130),
('14', '14. Contractor Management', '2. What process is followed for contractor management?', 'Appointment of the Contract Manager Risk register Contract Classification Category specifications Evaluation Criteria approved list of contractors/suppliers Pricing Schedule roles and responsibilities are clearly defined signed Agreement project is insured Contractor Execution Plan Approved Contractor Compliance File Contractor InductionAttendance Register. Employee Profile Dossier Completed Induction Indemnity Form Applicable permits and authorisations Completed Pre-site handover inspection Completed Site Access Certificate Progress Meeting minutes', '', 131),
('14', '14. Contractor Management', 'How are the contractors on-site being managed?', '1) Contractor Induction 2) Inspection and Audit reports and management of actions  3) Performance on-site 4) Deviation Management 5) Operational permits  / licence issued e.g. Hotwork permit', '', 132),
('14', '14. Contractor Management', 'What are the key activities that are followed to conduct close-out of the contract?', '1) Site inspection  2) Signed Final Handover and Close-out Inspection                                               3) Completed Contractor Compliance File  4) post-contract evaluation meeting minutes (performance statistics analysed to determine trends, lessons learnt, summary of the findings and future corrective actions)  5) Communicated findings and lessons learnt to the project initiator. 6) Updated contract register reflecting closing of project 7) Release of retention monies and performance bonds at the expiry', '', 133),
('15', '15. Integrated Assurance:', '1. How is Calibration Monitored?', '1. Calibration register and the schedule. 2. IsoMetrix status report. 3. Report on IsoMetrix.', '', 134),
('15', '15. Integrated Assurance:', '2. How is the Integrated Assurance established, monitored and gaps addressed?', '1. Integrated Assurance universe and plan status report 2. Assurance reports 3. Assurance oversight meeting report 4. IsoMetrix status report 5. Trend analysis report', '', 135),
('15', '15. Integrated Assurance:', '3. Verify if all the mandatory surveys are implementated and recommendations are addressed', 'Status report', '', 136),
('15', '15. Integrated Assurance:', '4. Does the business have a internal assurance schedule (Schedule of inspections, product audits)', '1. Scheduling of audits/inspections 2. Audit/inspection reports', '', 137),
('15', '15. Integrated Assurance:', '4. Does the business have mechanisms to track adherence to rolling stock maintenance plans, change out of components, time-based inspections, test, wheel monitoring, ITCMS etc)?', '1. Maintanance Engineering Stats and reports', '', 138),
('15', '15. Integrated Assurance:', '4. Are SHE compliance inspections scheduled and executed by relevant personnel? Does management implement recommendations made in these inspections:', '1. Actions plans and progress report (status)', '', 139),
('15', '15. Integrated Assurance:', '5. Are SHE Representative monthly inspections done?', '1. Inspection reports signed off by the employer/chairperson of the SHE Committee 2. Idenfied deviations receive attention from management (status) 3. Interview a SHE Representative', '', 140),
('15', '15. Integrated Assurance:', '10. Were all the previous audits findings of 2020/21 effectiviely and satisfactorily closed?', 'Evidence made available Repeat findings Ownership of the audit reports', '', 141),
('16', '16. Business Continuity Management:', '1. Is the Business Impact Analysis (BIA) conducted?', '1. Signed off Business Impact Analysis', 'No', 142),
('16', '16. Business Continuity Management:', '2. Business Continuity Plan documented, reviewed  and signed off?', '1. Signed off BCP', '', 143),
('16', '16. Business Continuity Management:', '3. Are the Control Self Assessment on BCM standards conducted?', '1. Annual Schedule 2. Control Self Assessment Report 3. Action plan with status', '', 144),
('16', '16. Business Continuity Management:', '4. How is the simulation of the BCP coordinated?', '1. Simulation plan 2. Meeting minutes of the simulation planning 3. Attendance register 4. Simulation report 5. Debrief session meeting minutes and report 6. Simulation results captured on IsoMetrix and report loaded on Sharepoint', '', 145),
('16', '16. Business Continuity Management:', '5. Are Critical business systems identified?', 'List of critical systems', '', 146),
('16', '16. Business Continuity Management:', '5. Verify if Critical systems are tested', 'Test report', '', 147),
('16', '16. Business Continuity Management:', '6. Are the BCP''s of suppliers of most urgent suplies or long lead time tested?', 'Test report', '', 148),
('16', '16. Business Continuity Management:', '7. Has a Multi disciplinary Incident plan been developed?', 'Integrated disaster management plan', '', 149),
('16', '16. Business Continuity Management:', '8. Verify if the Business Continuity training programme is developed, implemented and monitored via governance forums / any forum?', '1. Needs analysis 2. Training plan 3. Attendance registers 4. Training programme evaluation report', '', 150),
('16', '16. Business Continuity Management:', '5. Is there an Integrated  BCP’s of OD’s sharing the site available?', 'Integrated BCP', '', 151),
('17', '17. Human Factors Management:', '1. How is the Fitness for duty monitored? –', '1. Alignment on medical surveillance and employment of employees on chronic medication. 2. Adherence to the Medical surveillance plan 3. Compliance to Fit for duty declaration 4. Management of employees with chronic conditions', '', 152),
('17', '17. Human Factors Management:', '2. Verify if Management of the Risk profile is implemented', '1. Adherence to Quarterly review                 2. Management of risk pool personnel', '', 153),
('17', '17. Human Factors Management:', '3. What ergonomics assessments required and how are they managed?', '1. Human Factor in design  2. Ergonomics assessment schedule and status 3. Ergonomins assesment report 4. Corrective action plan monitoring status', '', 154),
('17', '17. Human Factors Management:', '4. Are all organisational and psychological processes in place?', '1. Recruitment and Selection (psychometric test, interview, experience and competence) 2. Wellness programme 3. Man-job specifications 4. Defined job classifications and additional checks required', '', 155),
('17', '17. Human Factors Management:', '5. Has the Occupational Risk Exposure Profile documented, communicated and monitored?', '1. Employee Occupational Risk Exposure Profile 2. Status report on Occupational Risk Exposure Profile', '', 156),
('17', '17. Human Factors Management:', '6. Has the Health risk assessments been conducted by the Occupational Health Practitioner ?', 'Health Risk register', '', 157),
('17', '17. Human Factors Management:', '7. What process is followed to manage fatigue ?', '1. Identified fatigue risks and recommended controls 2. Communication of the fatigue risks and controls', '', 158),
('17', '17. Human Factors Management:', '8. How is pregnancy being managed?', '1. Identified Risk associated with pregancy  2. Recommendations for alternative placement if applicable dependent on the risk', '', 159),
('17', '17. Human Factors Management:', '9. Verify if Employee Wellness programme is integrated to adress various interventions; including absenteeism management, stress management, awareness, support, guidance and case management', '1. Completed Return to Work Interview 2. Work life balance awareness 3. Absenteeism management programme ( trends analysis and case management) 4. Implementation plan of the Safety Behavioural Risk Assessment 5. Wellness events', '', 160),
('17', '17. Human Factors Management:', '10. What process are in place to manage stress?', '1. Health assessments; 2. Employee referral programs;  3. Rehabilitation; and 4. Return to work programs', '', 161),
('17', '17. Human Factors Management:', '11. What occupational health stressers are inherent to this environment?', '1. Noise, illumination, radiation, thermal stress, ventilation, dust, fumes, etc. 2. Frequency of the survey 3. Corrective Action Plans', '', 162),
('17', '17. Human Factors Management:', '12. How is overtime managed within the business to ensure management of fatigue', 'Overtime report (highest overtime earners)', '', 163),
('18', '18. Continual improvement:', 'Which Continual Improvement Initiatives are identified and how are they monitored? - Trending of occurences - Improving products and services - Improving the performace and effectiveness - Trending of Audit findings - Trending of Customer complaints', 'List with Continual Improvement initiatives and Project Plans.      - Examples of improvement can include correction, corrective action, continual improvement, breakthrough change, innovation and re-organization', '', 164);
